// ======================================================
// MATCH (Input2 Sheets7) vs (Input1 Sheets5) por 3 chaves
// Data / Código / Exames  X  Data do Cadastro / Registro do Paciente / SIGLA
// ✅ Retorna 1 item por match
// ✅ Retorna todas as variáveis do Input1 e do Input2
// ✅ Não depende de Loop Over Items3
// ✅ Se não houver match, retorna 1 item de controle
// ======================================================

const norm = (v) =>
  String(v ?? "")
    .replace(/\u00A0/g, " ")
    .replace(/\s+/g, " ")
    .trim()
    .toLowerCase();

function extrairDataBR(valor) {
  if (!valor) return "";
  const m = String(valor).match(/\b(\d{2}\/\d{2}\/\d{4})\b/);
  return m ? m[1] : String(valor).trim();
}

function makeKeyFromInput1(row) {
  const data = norm(extrairDataBR(row["Data"]));
  const codigo = norm(row["Código"]);
  const exame = norm(row["Exame"]);
  return `${data}♦${codigo}♦${exame}`;
}

function makeKeyFromInput2(row) {
  const data = norm(extrairDataBR(row["Data do Cadastro"]));
  const codigo = norm(row["Registro do Paciente"]);
  const exame = norm(row["SIGLA"]);
  return `${data}♦${codigo}♦${exame}`;
}

const input1 = $input.all(0); // Sheets5
const input2 = $input.all(1); // Sheets7

const index = new Map();

// indexa o input1
for (const it of input1) {
  const row1 = it.json || {};
  const key1 = makeKeyFromInput1(row1);

  if (!key1 || key1 === "♦♦") continue;

  if (!index.has(key1)) {
    index.set(key1, []);
  }

  index.get(key1).push(row1);
}

const out = [];

// procura itens do input2 no input1
for (const it of input2) {
  const row2 = it.json || {};
  const key2 = makeKeyFromInput2(row2);

  if (!key2 || key2 === "♦♦") continue;

  const encontrados = index.get(key2);
  if (!encontrados || encontrados.length === 0) continue;

  for (const row1 of encontrados) {
    out.push({
      json: {
        teveMatch: true,
        chaveMatch: key2,

        // campos do input1
        ...row1,

        // campos do input2 com prefixo
        ...Object.fromEntries(
          Object.entries(row2).map(([k, v]) => [`input2_${k}`, v])
        ),

        // objetos completos
        input1: { ...row1 },
        input2: { ...row2 },
      }
    });
  }
}

// se não houver match, retorna item de controle
if (out.length === 0) {
  return [
    {
      json: {
        teveMatch: false,
        totalMatches: 0,
        repetir: true
      }
    }
  ];
}

return out;

// Cada execução do loop traz 1 item
// O item atual já está em $json

return [
  {
    json: {
      id: $json.id,
      name: $json.name
    }
  }
];

const linhas = $input.all();

// ---------- util ----------
function extrairData(valor) {
  if (!valor) return null;
  const texto = String(valor).trim();
  const match = texto.match(/\b(\d{2}\/\d{2}\/\d{4})\b/);
  return match ? match[1] : null;
}

function removerZeroEsquerda(valor) {
  const texto = String(valor ?? "").trim();
  if (!texto) return texto;
  const semZeroEsquerda = texto.replace(/^0+/, "");
  return semZeroEsquerda || "0";
}

// ---------- nomeArquivo ----------
const loopCtx = $node["Loop Over Items3"]?.context || {};
const batchIndex =
  loopCtx.currentRunIndex ??
  loopCtx.currentBatchIndex ??
  loopCtx.itemIndex ??
  0;

const driveItems = $items("Google Drive6") || [];
const driveItem = driveItems[batchIndex] || driveItems[0] || null;

const nomeArquivoRaw = driveItem?.json?.name || $json?.name || null;

const nomeArquivo = nomeArquivoRaw
  ? String(nomeArquivoRaw)
      .replace(/\.[^.]+$/, "")
      .replace(/\d+/g, "")
      .replace(/[._\-\/]/g, " ")
      .replace(/\s+/g, " ")
      .trim()
  : null;

// ---------- retorno padrão quando não houver itens ----------
function retornoSemItens(motivo) {
  return [
    {
      json: {
        semItens: true,
        motivo,
        nomeArquivo,
        sistema: "WORKLAB",
        totalLinhasEntrada: linhas.length,
      },
    },
  ];
}

// se não veio nada no input
if (!linhas.length) {
  return retornoSemItens("Nenhum item recebido no input.");
}

// ======================================
// 1) Cabeçalho = linha real 6 da planilha
// ======================================
const headerItem = linhas.find(item => Number(item.json?.row_number) === 6);

if (!headerItem?.json) {
  return retornoSemItens("Cabeçalho da linha 6 não encontrado.");
}

const headerObj = headerItem.json;

// ======================================
// 2) Montar mapa de renomeação
// ======================================
const headerMap = {};

for (const [k, v] of Object.entries(headerObj)) {
  const nomeCabecalho = String(v ?? "").replace(/\s+/g, " ").trim();

  if (!nomeCabecalho) continue;

  // mapeia colunas técnicas col_X
  if (/^col_\d+$/i.test(k)) {
    headerMap[k] = nomeCabecalho;
  }

  // mapeia também a primeira coluna longa
  if (k === "Relatório Paciente por Convênio Detalhado") {
    headerMap[k] = nomeCabecalho; // vira "Data"
  }
}

// ======================================
// 3) Renomear colunas usando o headerMap
// ======================================
function renameColsToHeaders(obj) {
  const out = {};

  for (const [k, v] of Object.entries(obj || {})) {
    if (headerMap[k]) {
      out[headerMap[k]] = v;
    } else {
      out[k] = v;
    }
  }

  return out;
}

// ======================================
// 4) Dados = linhas após a linha 6
// ======================================
const dados = linhas.filter(item => Number(item.json?.row_number) > 6);

function isEmptyRow(obj) {
  return !Object.values(obj || {}).some(v => String(v ?? "").trim() !== "");
}

if (!dados.length) {
  return retornoSemItens("Não existem linhas de dados após o cabeçalho.");
}

// ======================================
// 5) Resultado final
// ======================================
const resultado = dados
  .filter(item => !isEmptyRow(item.json))
  .map(item => {
    const renamed = renameColsToHeaders(item.json);

    // remove zero à esquerda em Código
    if (renamed["Código"] !== undefined && renamed["Código"] !== null) {
      renamed["Código"] = removerZeroEsquerda(renamed["Código"]);
    }

    // remove zero à esquerda em Convênio Sigla
    if (renamed["Convênio Sigla"] !== undefined && renamed["Convênio Sigla"] !== null) {
      renamed["Convênio Sigla"] = removerZeroEsquerda(renamed["Convênio Sigla"]);
    }

    const dataFormatada = extrairData(renamed["Data"]) || null;
    const dataRelatorio = dataFormatada;

    return {
      json: {
        ...renamed,
        Data: dataFormatada,
        dataRelatorio,
        nomeArquivo,
        sistema: "WORKLAB",
      },
    };
  })
  .filter(item => String(item.json?.Data ?? "").trim() !== "");

// se após os filtros não sobrar nada
if (!resultado.length) {
  return retornoSemItens("Nenhuma linha válida encontrada após filtrar Data vazia.");
}

return resultado;

